import { Avatar, Badge, Card, CardContent, CardHeader, Divider, IconButton, Link, Typography } from '@material-ui/core'
import { MoreVert } from '@material-ui/icons'
import { makeStyles } from '@material-ui/styles'
import React from 'react'

const StyledBadge = withStyles((theme) => ({
  badge: {
    backgroundColor: '#44b700',
    color: '#44b700',
    boxShadow: `0 0 0 2px ${theme.palette.background.paper}`,
    '&::after': {
      position: 'absolute',
      top: 0,
      left: 0,
      width: '100%',
      height: '100%',
      borderRadius: '50%',
      animation: '$ripple 1.2s infinite ease-in-out',
      border: '1px solid currentColor',
      content: '""',
    },
  },
  '@keyframes ripple': {
    '0%': {
      transform: 'scale(.8)',
      opacity: 1,
    },
    '100%': {
      transform: 'scale(2.4)',
      opacity: 0,
    },
  },
}))(Badge);

const useStyle = makeStyles(theme => {
  return {
    root: {
      // '& .MuiCard-root:hover': {
      // boxShadow: 'none',
      // background: 'none'
    },
    avatar: {
      background: '#162276',
      width: theme.spacing(7),
      height: theme.spacing(7),
    },
    openClassroom: {
      background: '#162276'
    }

  }
})

export default function SubjectCards({ subject }) {
  const classes = useStyle()
  return (
    <div>
      <IconButton>
                <MoreVert />
              </IconButton>
      <Card elevation={1}>
          <CardHeader
            avatar={
              <StyledBadge
        overlap="circular"
        anchorOrigin={{
          vertical: 'bottom',
          horizontal: 'right',
        }}
        variant="dot"
      >
              <Avatar className={classes.avatar} sizes='medium'>
                P
              </Avatar>
              </StyledBadge>
            }

            title={subject.title}
            subheader={subject.instructor}
          />

          <Divider />
          <CardContent>
            <Typography>
              {subject.body}
            </Typography>
          </CardContent>
      </Card>
    </div>
  )
}
